# --- 3. PLOTTING FUNCTION ---
def plot_per_class(nested_dict, title):
    fig, axes = plt.subplots(2, 4, figsize=(18, 10))
    axes = axes.flatten()
    sorted_keys = ["1A", "1B", "2Peso", "5A", "5B", "10A", "10B", "20A"]
    
    for i, coin in enumerate(sorted_keys):
        ax = axes[i]
        raw_list = []
        if coin in nested_dict:
            for group_list in nested_dict[coin]:
                raw_list.extend(group_list)
        
        if not raw_list:
            ax.text(0.5, 0.5, "NO DATA", ha='center', va='center', color='#444b5a')
            ax.set_title(f"Class {coin}", color='#444b5a')
            continue

        h_arr = np.array(raw_list)
        h_cum = np.cumsum(h_arr)
        t_cum = np.cumsum(1 - h_arr)
        
        total = len(h_arr)
        final_h = h_cum[-1]
        final_t = t_cum[-1]

        ax.plot(h_cum, color=color_heads, linewidth=1.8, label=f"Heads: {final_h} ({(final_h/total)*100:.1f}%)")
        ax.plot(t_cum, color=color_tails, linewidth=1.8, label=f"Tails: {final_t} ({(final_t/total)*100:.1f}%)")
        
        ax.set_title(f"Class {coin}", fontsize=11, fontweight='bold', pad=10)
        ax.grid(True, alpha=0.1)
        ax.legend(loc='upper left', prop={'size': 7})

    plt.suptitle(title, fontsize=18, fontweight='bold', y=0.98)
    plt.tight_layout(rect=[0, 0.03, 1, 0.95])
    plt.show()

# --- 4. EXECUTION ---
plot_per_class(table_data, "TABLE SURFACE STATISTICS - CUMULATIVE SUMMARY")
plot_per_class(tiles_data, "TILES SURFACE STATISTICS - CUMULATIVE SUMMARY")